// --- Backward-compatible aliases for existing PootBox.tsx ---

/** @deprecated Use BUILT_IN_SOUNDS with bucket="animal" — persists for PootBox.tsx until v46e */
export const CIRCLES: Circle[] = BUILT_IN_SOUNDS
  .filter(s => s.bucket === "animal")
  .map(s => ({
    id: s.key,
    emoji: s.emoji,
    color: "transparent",
    shadow: "transparent",
    hatchEmoji: "🐦",
    sounds: [s.file],
    radius: 32,
    mass: 1,
  }));

/** @deprecated Use MAX_BUBBLES_PER_PAGE — persists for PootBox.tsx until v46e */
export const MAX_CUSTOM_CIRCLES = MAX_BUBBLES_PER_PAGE;

// --- Settings helpers ---

export function loadSettings(): { volume: number; reducedMotion: boolean } {
  try {
    const raw = localStorage.getItem(SETTINGS_KEY);
    if (raw) return { ...DEFAULT_SETTINGS, ...JSON.parse(raw) };
  } catch { /* ignore */ }
  return DEFAULT_SETTINGS;
}

export function saveSettings(s: { volume: number; reducedMotion: boolean }): void {
  try {
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(s));
  } catch { /* ignore */ }
}